targets.root_selector:
$map(Results, function($v){
  {
    "Workflow_InstId": $v.InstId,
    "Workflow_TraceId": $v.TraceId,
    "Workflow_Message": $v.Message.Message,
    "Workflow_Severity": $v.Message.Severity,
    "Workflow_Name": $v.Name,
    "Workflow_Src": $v.Src,
   "Workflow_Moid": $v.Moid,
    "Workflow_Status": $v.Status,
    "Workflow_StartTime": $v.StartTime,
    "Workflow_EndTime": $v.EndTime,
    "TaskInfos": $v.TaskInfos[Status = 'FAILED'].{"Status": Status,  "InstId": InstId, "Moid": Moid, "RunningInstId": RunningInstId, "FailureReason": FailureReason}
  }
})
